PixelShader.code:
sampler2D TexA : register(s0);
sampler2D TexB : register(s1);
float Progress : register(c0);
float LensType : register(c1);
float Zoom : register(c2);
float2 Center : register(c3);
float Softness : register(c4);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 d = uv - Center;
  float dist = length(d);
  float r = lerp(1.0, Zoom, Progress);
  float2 uvLens = Center + d / r;
  float4 a = tex2D(TexA, uv);
  float4 b = tex2D(TexB, uvLens);
  float edge = smoothstep(0.0, Softness, Progress) * smoothstep(1.0, 1.0 - Softness, Progress);
  return lerp(a, b, Progress);
}

sampler2D Tex : register(s0);
float Strength : register(c0);
float2 TexelSize : register(c1);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float4 c  = tex2D(Tex, uv);
  float4 n  = tex2D(Tex, uv + float2(0, -TexelSize.y));
  float4 s  = tex2D(Tex, uv + float2(0,  TexelSize.y));
  float4 e  = tex2D(Tex, uv + float2( TexelSize.x, 0));
  float4 w  = tex2D(Tex, uv + float2(-TexelSize.x, 0));
  float4 avg = (n + s + e + w) * 0.25;
  return lerp(c, avg, Strength);
}

sampler2D Tex : register(s0);
float Amount : register(c0);
float2 TexelSize : register(c1);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float4 c = tex2D(Tex, uv);
  float4 n = tex2D(Tex, uv + float2(0, -TexelSize.y));
  float4 s = tex2D(Tex, uv + float2(0,  TexelSize.y));
  float4 e = tex2D(Tex, uv + float2( TexelSize.x, 0));
  float4 w = tex2D(Tex, uv + float2(-TexelSize.x, 0));
  float4 laplacian = c * 4.0 - (n + s + e + w);
  return c + laplacian * Amount;
}

sampler2D Tex : register(s0);
float Amount : register(c0);
float Angle : register(c1);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float rad = Angle * 3.14159265 / 180.0;
  float2 offset = float2(cos(rad), sin(rad)) * Amount;
  float r = tex2D(Tex, uv + offset).r;
  float g = tex2D(Tex, uv).g;
  float b = tex2D(Tex, uv - offset).b;
  float a = tex2D(Tex, uv).a;
  return float4(r, g, b, a);
}

sampler2D Tex : register(s0);
float FrequencyX : register(c0);
float FrequencyY : register(c1);
float AmplitudeX : register(c2);
float AmplitudeY : register(c3);
float Time : register(c4);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 warp;
  warp.x = uv.x + sin(uv.y * FrequencyY + Time) * AmplitudeX;
  warp.y = uv.y + cos(uv.x * FrequencyX + Time) * AmplitudeY;
  return tex2D(Tex, warp);
}

sampler2D Tex : register(s0);
float Strength : register(c0);
float LineWidth : register(c1);
float Angle : register(c2);
float2 TexelSize : register(c3);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float rad = Angle * 3.14159265 / 180.0;
  float2 dir = float2(cos(rad), sin(rad)) * TexelSize * LineWidth;
  float4 c0 = tex2D(Tex, uv);
  float4 c1 = tex2D(Tex, uv + dir);
  float edge = length(c0.rgb - c1.rgb) * Strength;
  float etch = 1.0 - saturate(edge);
  return float4(etch, etch, etch, c0.a);
}

sampler2D Tex : register(s0);
float Frequency : register(c0);
float Offset : register(c1);
float Intensity : register(c2);
float Vertical : register(c3);
float3 hsv2rgb(float3 c) {
  float4 K = float4(1.0, 2.0/3.0, 1.0/3.0, 3.0);
  float3 p = abs(frac(c.xxx + K.xyz) * 6.0 - K.www);
  return c.z * lerp(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}
float4 main(float2 uv : TEXCOORD) : COLOR {
  float4 orig = tex2D(Tex, uv);
  float pos = Vertical > 0.5 ? uv.y : uv.x;
  float hue = frac(pos * Frequency + Offset);
  float3 rainbow = hsv2rgb(float3(hue, 1.0, 1.0));
  return float4(lerp(orig.rgb, orig.rgb * rainbow, Intensity), orig.a);
}

sampler2D Tex : register(s0);
float Segments : register(c0);
float Rotation : register(c1);
float2 Center : register(c2);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 d = uv - Center;
  float angle = atan2(d.y, d.x);
  float dist = length(d);
  float pi = 3.14159265;
  float seg = pi * 2.0 / Segments;
  angle += Rotation * pi / 180.0;
  angle = fmod(abs(angle), seg);
  if (angle > seg * 0.5) angle = seg - angle;
  float2 nuv = Center + float2(cos(angle), sin(angle)) * dist;
  return tex2D(Tex, nuv);
}

sampler2D Tex : register(s0);
float FrequencyH : register(c0);
float FrequencyV : register(c1);
float AmplitudeH : register(c2);
float AmplitudeV : register(c3);
float Phase : register(c4);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 wuv;
  wuv.x = uv.x + sin(uv.y * FrequencyV + Phase) * AmplitudeH;
  wuv.y = uv.y + sin(uv.x * FrequencyH + Phase) * AmplitudeV;
  return tex2D(Tex, wuv);
}

sampler2D Tex : register(s0);
float Angle : register(c0);
float Radius : register(c1);
float2 Center : register(c2);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 d = uv - Center;
  float dist = length(d);
  float pi = 3.14159265;
  float theta = Angle * pi / 180.0 * max(0.0, 1.0 - dist / Radius);
  float cosA = cos(theta), sinA = sin(theta);
  float2 rotated = float2(cosA * d.x - sinA * d.y, sinA * d.x + cosA * d.y);
  return tex2D(Tex, Center + rotated);
}

sampler2D Tex : register(s0);
float Amount : register(c0);
float Radius : register(c1);
float2 Center : register(c2);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 d = uv - Center;
  float dist = length(d);
  float pi = 3.14159265;
  float factor = max(0.0, 1.0 - dist / Radius);
  float theta = Amount * pi * factor;
  float cosA = cos(theta), sinA = sin(theta);
  float2 rot = float2(cosA*d.x - sinA*d.y, sinA*d.x + cosA*d.y);
  return tex2D(Tex, Center + rot);
}

sampler2D Tex : register(s0);
float OffsetX : register(c0);
float OffsetY : register(c1);
float Wrap : register(c2);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 nuv = uv + float2(OffsetX, OffsetY);
  if (Wrap > 0.5)
    nuv = frac(nuv);
  else
    nuv = clamp(nuv, 0.0, 1.0);
  return tex2D(Tex, nuv);
}

sampler2D Tex : register(s0);
float Amount : register(c0);
float2 Center : register(c1);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 d = uv - Center;
  float dist = length(d);
  float scale = (Amount > 0.0)
    ? (1.0 + dist * Amount)
    : (1.0 / (1.0 - dist * Amount));
  float2 nuv = Center + d / scale;
  return tex2D(Tex, nuv);
}

sampler2D Tex : register(s0);
float ShearX : register(c0);
float ShearY : register(c1);
float Wrap : register(c2);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 nuv;
  nuv.x = uv.x + ShearX * uv.y;
  nuv.y = uv.y + ShearY * uv.x;
  if (Wrap > 0.5)
    nuv = frac(nuv);
  else
    nuv = clamp(nuv, 0.0, 1.0);
  return tex2D(Tex, nuv);
}

sampler2D Tex : register(s0);
float2 StartPos : register(c0);
float2 EndPos : register(c1);
float StartScale : register(c2);
float EndScale : register(c3);
float Progress : register(c4);
float4 main(float2 uv : TEXCOORD) : COLOR {
  float2 center = lerp(StartPos, EndPos, Progress);
  float scale = lerp(StartScale, EndScale, Progress);
  float2 nuv = center + (uv - 0.5) / scale;
  return tex2D(Tex, nuv);
}
